/** Generate a valid test CPF (without validation, just for filling forms) */
export function generateTestCpf(): string {
  const n = (max: number) => Math.floor(Math.random() * max)
  const n9 = `${n(9)}${n(9)}${n(9)}${n(9)}${n(9)}${n(9)}${n(9)}${n(9)}${n(9)}`
  // Simple CPF-like number for testing
  return `${n9.slice(0, 3)}.${n9.slice(3, 6)}.${n9.slice(6, 9)}-${n(9)}${n(9)}`
}

