/** Generate test unavailability period data */
export function generateTestUnavailabilityData() {
  const today = new Date()
  const startDate = new Date(today)
  startDate.setDate(today.getDate() + Math.floor(Math.random() * 30) + 10)

  const endDate = new Date(startDate)
  endDate.setDate(startDate.getDate() + Math.floor(Math.random() * 10) + 3)

  const reasons = ['Férias', 'Licença médica', 'Plantão externo', 'Congresso', 'Curso']

  return {
    start_date: startDate.toISOString().split('T')[0],
    end_date: endDate.toISOString().split('T')[0],
    reason: reasons[Math.floor(Math.random() * reasons.length)],
  }
}

/** Generate test message data */
export function generateTestMessageData() {
  const subjects = [
    'Encaminhamento de paciente',
    'Solicitação de exames',
    'Resultado de exames',
    'Confirmação de consulta',
    'Relatório de atendimento',
  ]

  const contents = [
    'Prezado(a), conforme conversamos, estou encaminhando o paciente para avaliação especializada.',
    'Solicito a realização dos exames conforme protocolo estabelecido.',
    'Segue em anexo o resultado dos exames solicitados na última consulta.',
    'Confirmo o agendamento da consulta para a data prevista.',
    'Encaminho o relatório de atendimento para análise.',
  ]

  return {
    subject: subjects[Math.floor(Math.random() * subjects.length)],
    content: contents[Math.floor(Math.random() * contents.length)],
  }
}
